import io.codenode.addresses.AddressesViewModel

@Composable
fun Addresses(
    viewModel: AddressesViewModel,
    modifier: Modifier = Modifier
) {
    val addresses by viewModel.addresses.collectAsState()
    var selectedId by remember { mutableStateOf<Long?>(null) }
    var showAddForm by remember { mutableStateOf(false) }
    var showUpdateForm by remember { mutableStateOf(false) }
    var showRemoveConfirmation by remember { mutableStateOf(false) }

    val selectedItem = addresses.find { it.id == selectedId }

    // Clear selection if the selected item was removed externally
    LaunchedEffect(addresses, selectedId) {
        if (selectedId != null && selectedItem == null) {
            selectedId = null
        }
    }

    if (showAddForm) {
        AddUpdateAddress(
            existingItem = null,
            onSave = { item ->
                viewModel.addEntity(item)
                showAddForm = false
            },
            onCancel = { showAddForm = false },
            modifier = modifier
        )
        return
    }

    if (showUpdateForm && selectedItem != null) {
        AddUpdateAddress(
            existingItem = selectedItem,
            onSave = { item ->
                viewModel.updateEntity(item)
                showUpdateForm = false
                selectedId = null
            },
            onCancel = { showUpdateForm = false },
            modifier = modifier
        )
        return
    }

    Column(
        modifier = modifier.fillMaxSize().padding(16.dp)
    ) {
        Text(
            text = "Addresses",
            style = MaterialTheme.typography.headlineMedium,
            modifier = Modifier.padding(bottom = 16.dp)
        )

        // Header row
        AddressHeaderRow()
        Divider()

        // List or empty state
        Box(modifier = Modifier.weight(1f)) {
            if (addresses.isEmpty()) {
                Text(
                    text = "No addresses yet",
                    style = MaterialTheme.typography.bodyLarge,
                    modifier = Modifier.align(Alignment.Center)
                )
            } else {
                LazyColumn(modifier = Modifier.fillMaxSize()) {
                    items(addresses, key = { it.id }) { item ->
                        AddressRow(
                            item = item,
                            isSelected = item.id == selectedId,
                            onClick = {
                                selectedId = if (selectedId == item.id) null else item.id
                            }
                        )
                    }
                }
            }
        }

        // Button row
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 16.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = { showAddForm = true }) {
                Text("Add")
            }
            Button(
                onClick = { showUpdateForm = true },
                enabled = selectedItem != null
            ) {
                Text("Update")
            }
            Button(
                onClick = { showRemoveConfirmation = true },
                enabled = selectedItem != null
            ) {
                Text("Remove")
            }
        }

        if (showRemoveConfirmation && selectedItem != null) {
            AlertDialog(
                onDismissRequest = { showRemoveConfirmation = false },
                title = { Text("Remove this item?") },
                text = { Text("Are you sure you want to remove this address?") },
                confirmButton = {
                    TextButton(onClick = {
                        viewModel.removeEntity(selectedItem)
                        selectedId = null
                        showRemoveConfirmation = false
                    }) {
                        Text("Confirm")
                    }
                },
                dismissButton = {
                    TextButton(onClick = { showRemoveConfirmation = false }) {
                        Text("Cancel")
                    }
                }
            )
        }
    }
}

